#include <stdio.h>
#include <stdlib.h>
#include <limits.h>
#define INF INT_MAX
#define MAX_N 1000
#define MAX_F 1000
#define MAX_M 100000
#define MAX_Q 1000

struct Edge {
    int to;
    int weight;
};

struct Graph {
    int numNodes;
    int numEdges;
    struct Edge* edges;
};

void dijkstra(struct Graph* graph, int start, int* distances) {
    for (int i = 0; i < graph->numNodes; i++) {
        distances[i] = INF;
    }
    distances[start] = 0;
    int* visited = (int*) malloc(graph->numNodes * sizeof(int));
    for (int i = 0; i < graph->numNodes; i++) {
        visited[i] = 0;
    }
    for (int i = 0; i < graph->numNodes; i++) {
        int minDistance = INF;
        int minIndex = -1;
        for (int j = 0; j < graph->numNodes; j++) {
            if (!visited[j] && distances[j] < minDistance) {
                minDistance = distances[j];
                minIndex = j;
            }
        }
        visited[minIndex] = 1;
        for (int j = 0; j < graph->numEdges; j++) {
            if (graph->edges[j].to == minIndex) {
                int neighbor = graph->edges[j].to;
                int weight = graph->edges[j].weight;
                if (distances[minIndex] + weight < distances[neighbor]) {
                    distances[neighbor] = distances[minIndex] + weight;
                }
            }
        }
    }
    free(visited);
}

int main() {
    int N, F, M;
    scanf("%d %d %d", &N, &F, &M);
    struct Graph* graph = (struct Graph*) malloc(sizeof(struct Graph));
    graph->numNodes = N * F;
    graph->numEdges = M;
    graph->edges = (struct Edge*) malloc(M * sizeof(struct Edge));
    for (int i = 0; i < M; i++) {
        int bi, fi, T, bj, fj;
        scanf("%d %d %d %d %d", &bi, &fi, &T, &bj, &fj);
        graph->edges[i].to = (bj - 1) * F + fj - 1;
        graph->edges[i].weight = T;
    }
    int Q;
    scanf("%d", &Q);
    for (int i = 0; i < Q; i++) {
        int bq, fq;
        scanf("%d %d", &bq, &fq);
        int* distances = (int*) malloc(graph->numNodes * sizeof(int));
        dijkstra(graph, (bq - 1) * F + fq - 1, distances);
        int sum = 0;
        for (int j = 0; j < graph->numNodes; j++) {
            if (j / F != bq - 1) {
                sum += distances[j];
            }
        }
        printf("%d\n", sum);
        free(distances);
    }
    free(graph->edges);
    free(graph);
    return 0;
}

