#include <iostream>
#include <vector>
#include <limits>
#include <queue>
using namespace std;

struct Edge {
    int to;
    int weight;
};

struct Graph {
    int numNodes;
    vector<Edge> edges;
};

void dijkstra(Graph& graph, int start, vector<int>& distances) {
    distances.assign(graph.numNodes, INT_MAX);
    distances[start] = 0;
    priority_queue<pair<int, int>, vector<pair<int, int>>, greater<pair<int, int>>> pq;
    pq.push({0, start});
    while (!pq.empty()) {
        int current = pq.top().second;
        pq.pop();
        for (const auto& edge : graph.edges) {
            if (edge.to == current) {
                int neighbor = edge.to;
                int weight = edge.weight;
                if (distances[current] + weight < distances[neighbor]) {
                    distances[neighbor] = distances[current] + weight;
                    pq.push({distances[neighbor], neighbor});
                }
            }
        }
    }
}

int main() {
    int N, F, M;
    cin >> N >> F >> M;
    Graph graph;
    graph.numNodes = N * F;
    for (int i = 0; i < M; i++) {
        int bi, fi, T, bj, fj;
        cin >> bi >> fi >> T >> bj >> fj;
        graph.edges.push_back({(bj - 1) * F + fj - 1, T});
    }
    int Q;
