import java.util.PriorityQueue;
import java.util.Scanner;

public class Main {
    static class Edge {
        int to;
        int weight;
        Edge(int to, int weight) {
            this.to = to;
            this.weight = weight;
        }
    }

    static class Graph {
        int numNodes;
        Edge[] edges;
    }

    public static void dijkstra(Graph graph, int start, int[] distances) {
        for (int i = 0; i < graph.numNodes; i++) {
            distances[i] = Integer.MAX_VALUE;
        }
        distances[start] = 0;
        PriorityQueue<int[]> pq = new PriorityQueue<>((a, b) -> a[0] - b[0]);
        pq.offer(new int[] {0, start});
        while (!pq.isEmpty()) {
            int[] current = pq.poll();
            for (Edge edge : graph.edges) {
                if (edge.to == current[1]) {
                    int neighbor = edge.to;
                    int weight = edge.weight;
                    if (distances[current[1]] + weight < distances[neighbor]) {
                        distances[neighbor] = distances[current[1]] + weight;
                        pq.offer(new int[] {distances[neighbor], neighbor});
                    }
                }
            }
        }
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int N = scanner.nextInt();
        int F = scanner.nextInt();
        int M = scanner.nextInt();
        Graph graph = new Graph();
        graph.numNodes = N * F;
        graph.edges = new Edge[M];
        for (int i = 0; i < M; i++) {
            int bi = scanner.nextInt();
            int fi = scanner.nextInt();
            int T = scanner.nextInt();
            int bj = scanner.nextInt();
            int fj = scanner.nextInt();
            graph.edges[i] = new Edge((bj - 1) * F + fj - 1, T);
        }
        int Q = scanner.nextInt();
        for (int i = 0; i < Q; i++) {
            int bq = scanner.nextInt();
            int fq = scanner.nextInt();
            int[] distances = new int[graph.numNodes];
            dijkstra(graph, (bq - 1) * F + fq - 1, distances);
            int sum = 0;
            for (int j = 0; j < graph.numNodes; j++) {
                if (j / F != bq - 1) {
                    sum += distances[j];
                }
            }
            System.out.println(sum);
        }
    }
}

